<?php
namespace App\Domain\GameHome\Admin;use App\Domain\GameHome\GameHomeCardDestinationResolver;use App\Models\GameHomeCard;use Illuminate\Support\Facades\DB;use InvalidArgumentException;
final class GameHomeCardService{private $resolver;public function __construct(GameHomeCardDestinationResolver $resolver){$this->resolver=$resolver;}public function save(array $data,GameHomeCard $card=null){$value=$this->resolver->validateConfiguration($data['destination_type'],isset($data['destination_value'])?$data['destination_value']:null);return DB::transaction(function()use($data,$card,$value){$target=$card?:new GameHomeCard();$target->fill(['name'=>trim($data['name']),'code'=>trim($data['code']),'destination_type'=>$data['destination_type'],'destination_value'=>$value,'sort_order'=>(int)$data['sort_order'],'is_active'=>(bool)$data['is_active'],'opens_new_tab'=>(bool)$data['opens_new_tab']]);$target->save();return$target;},3);}public function setActive(GameHomeCard $card,$active){$card->is_active=(bool)$active;$card->save();return$card;}public function delete(GameHomeCard $card){$card->delete();}}
